script:
if not doc.contract_start_date or not doc.contract_end_date:
    frappe.throw("Start Date and End Date are required.")

if doc.contract_start_date >= doc.contract_end_date:
    frappe.throw("End Date must be after Start Date.")

if not doc.billing_type:
    frappe.throw("Billing Type is required.")

if not doc.billing_frequency:
    frappe.throw("Billing Frequency is required.")

if not doc.billing_amount or doc.billing_amount <= 0:
    frappe.throw("Billing Amount must be greater than zero.")
